import Page from 'components/Page';
import React from 'react';
import {
  Button,
  Card,
  CardBody,
  CardHeader,
  Col,
  Form,
  FormFeedback,
  FormGroup,
  FormText,
  Input,
  Label,
  Row,
  Alert,
  Table,
} from 'reactstrap';
import states from "../api/states";
import yearsofex from "../api/yearsofex";
import { newExpense, findExpenses,} from "../api/api";
import AsyncStorage from '@callstack/async-storage';
import conf from "../api/config";
import PageSpinner from 'components/PageSpinner';
import MUIDataTable from "mui-datatables";
import CustomToolbarSelectExpenses from "../components/CustomToolbarSelectExpenses";
class ExpensesPage extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
          narration : '',
          person : '',
          fee:'',
          xtoken:'',
          msg: '',
          error: '',
          preload:false,
          downloadFile:true,
          data: [],
        };
        AsyncStorage.getItem(conf.secret)
        .then((results) => {
          if( results !== null )
          {
            let obje_results = JSON.parse(results);
            this.setState({
              ...this.state,
              xtoken : obje_results.user.token,
            });
            findExpenses(obje_results.user.token).then((response) => {
                // console.log('data-data', response.data);
                this.setState({
                    ...this.state,
                    data:response.data,
                });
            }).catch((respError) => {});
          }
        })
        .catch((error) => {
          console.log('storage error', error);
        });
    }
    componentDidMount() {
    }

    rerenderParentCallback = () => {
      findExpenses (this.state.xtoken).then((response) => {
        this.setState({
            ...this.state,
            data:response.data,
        });
      }).catch((respError) => {
      });
    }
    
    handleNarrationInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, narration: v,});
    }
    handlePersonInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, person: v,});
    }
    handleFeeInput = (event) => {
      const v = event.target.value;
      this.setState({...this.state, fee: v,});
    }
    handleSaveChanges = () => {
        // console.log('so far', this.state);
        this.setState({
          ...this.state,
          preload:true,
        });
        newExpense(this.state.xtoken, this.state)
        .then((response) => {
            // console.log('so_far', response);
            if( response.status === 200)
            {
                this.setState({
                    ...this.state,
                    narration : '',
                    person : '',
                    fee:'',
                    msg: response.message,
                    data: response.data,
                    error: '',
                    preload:false,
                });

                this.forceUpdate();
            }
            else
            {
                this.setState({
                    ...this.state,
                    error: response.message,
                    msg: '',
                    preload:false,
                });
            }
        })
        .catch((error) => {
            this.setState({
                ...this.state,
                error: 'Connection error occured',
                preload:false,
            });
            console.log('error', error);
        });
    }
    render() {
        const columns = [
            {
              name: 'Id',
              options: {
                display: false
              }
            },
            'Person(s)',
            'Year/Term',
            'Narration',
            'Amount',
        ];

        const data2 = () => {
          let rtn = [];
          this.state.data.map(item => {
            rtn.push([
                item.id,
                item.person,
                item.ylabel,
                item.narration,
                item.fee,
            ]);
          });
          return rtn;
        }
      
        const options = {
            filter: true,
            selectableRows: 'single',
            selectableRowsOnClick:true,
            filterType: 'dropdown',
            responsive: 'vertical',
            draggableColumns: {
              enabled: true
            },
            rowsPerPage: 5,
            selectToolbarPlacement: 'replace',
            customToolbarSelect: (selectedRows, displayData, setSelectedRows) => (
              <CustomToolbarSelectExpenses rerenderParentCallback={this.rerenderParentCallback} selectedRows={selectedRows} displayData={displayData} setSelectedRows={setSelectedRows}  originalData={this.state.data} Xtoken={this.state.xtoken}/>
            ),
            downloadOptions: {
                filename: 'school-data-excel-format.csv',
                separator: ';',
                filterOptions: {
                  useDisplayedColumnsOnly: true,
                  useDisplayedRowsOnly: true,
                }
            },
            onDownload: (buildHead, buildBody, columns, data2) => {
              if (this.state.downloadFile) {
                let val= `${buildHead(columns)}${buildBody(data2)}`.trim();
                return val;
              }
      
              return false;
            },
            onRowSelectionChange: (currentRowsSelected, allRows, rowsSelected) => {
              // console.log('currentRowsSelected', currentRowsSelected);
            },
            onRowsDelete: rowsDeleted => {
              // console.log(rowsDeleted, 'were deleted!');
            },
            onChangePage: numberRows => {
              // console.log(numberRows);
            },
            onSearchChange: searchText => {
              // console.log(searchText);
            },
            onColumnSortChange: (column, direction) => {
              // console.log(column, direction);
            },
            onViewColumnsChange: (column, action) => {
              // console.log(column, action);
            },
            onFilterChange: (column, filters) => {
              // console.log(column, filters);
            },
            onCellClick: (cellIndex, rowIndex) => {
              // console.log(cellIndex, rowIndex);
            },
            onRowClick: (rowData, rowState) => {
              // console.log(rowData, rowState);
            },
        };
      return (
        <Page title="Accounts - Expenses" breadcrumbs={[{ name: 'Expenses', active: true }]}>
          <Row>
            <Col xl={12} lg={12} md={12}>
              <Card>
                <CardHeader>Create Expense {this.state.preload && (<PageSpinner/>)} </CardHeader>
                {this.state.error.length > 0 && (
                    <Alert color="danger">{this.state.error}</Alert>
                )}
                {this.state.msg.length > 0 && (
                    <Alert color="success">{this.state.msg}</Alert>
                )}
              </Card>
            </Col>
          </Row>

          <Row>
            <Col xl={3} lg={12} md={12}>
              <Card>
                <CardBody>
                <Form>
                    <FormGroup>
                      <Label for="exampleSelect">Narration*</Label>
                      <Input onChange={this.handleNarrationInput}
                        type="text" 
                        value={this.state.narration}
                        name="frm"
                        placeholder=""
                      />
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
            <Col xl={4} lg={12} md={12}>
              <Card>
                <CardBody>
                  <Form>
                  <FormGroup>
                      <Label for="exampleEmail">Associated person(name, adm no etc)*</Label>
                      <Input onChange={this.handlePersonInput}
                        type="text" 
                        value={this.state.person}
                        name="frm"
                        placeholder=""
                      />
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
            <Col xl={2} lg={12} md={12}>
              <Card>
                <CardBody>
                  <Form>
                  <FormGroup>
                      <Label for="exampleEmail">Amount in KES*</Label>
                      <Input onChange={this.handleFeeInput}
                        type="number" 
                        value={this.state.fee}
                        name="frm"
                        placeholder=""
                      />
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>              
            <Col xl={3} lg={12} md={12}>
              <Card>
                <CardBody>
                  <Form>
                      <br></br>
                    <FormGroup check row>
                      <Col sm={{ size: 10, offset: 2 }}>
                        <Button type="button" onClick={this.handleSaveChanges}>Add expense</Button>
                      </Col>
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
          </Row>

          <Row>
            <Col xl={12} lg={12} md={12}>
              <Card>
                <CardBody>
                    <MUIDataTable title={'List of Expenses'}
                    data={this.state.data.map(item => {
                      return [
                        item.id,
                        item.person,
                        item.ylabel,
                        item.narration,
                        item.fee,
                      ]
                    })} columns={columns} options={options} />
                </CardBody>
              </Card>
            </Col>
          </Row>
    
        </Page>
      );
    }
}
export default ExpensesPage;
